// // This is a synchronous down counter with an asynchronous reset
module up_counter_sync_reset (
    input clk,
    input reset,
    output reg [3:0] count
);

    always @(posedge clk) begin
        if (reset) begin
            count <= 4'b0000;
        end else begin
            count <= count + 1;
        end
    end

endmodule
